(1, 'HT202511095051', 'sales', 7, '深圳市博远联合电子有限公司', '2025-11-09', 8200.00, '签订合同后7日内支付30%预付款，货物交付后支付60%，验收合格后支付10%。', '收到预付款后15个工作日内交付，交付地点为乙方指定地址。', '硬件产品质保3年，设备人为损坏及进液体腐蚀虫蚀雷击不保修，软件产品提供免费技术支持。', NULL, NULL, NULL, NULL, NULL, NULL, 'draft', '', 1, '2025-11-09 08:45:13'),
(14, 'HT202604013197', 'sales', 26, '惠州市天成云天信息技术有限公司', '2026-04-01', 12400.00, '租金按月支付，每月1日前支付当月租金，逾期超过7日加收滞纳金。', '设备由甲方送货上门，乙方验收签字后生效。租期届满前3日乙方应通知甲方安排取货，设备应保持完好。', '租赁期间因乙方原因造成设备损坏或丢失，乙方按设备市场价格赔偿。正常使用磨损不在赔偿范围内。', '', NULL, NULL, '按照国家相关施工规范及行业标准验收，甲方在收到竣工报告后5个工作日内组织验收，验收合格后签署竣工验收单。', '一般故障：4小时内响应，24小时内解决；\r\n重大故障：2小时内响应，8小时内解决；\r\n紧急故障：30分钟内响应，4小时内解决。', 'onsite', 'draft', '', 1, '2026-04-01 11:19:11'),
(15, 'HT202604019070', 'construction', 37, '广州市万象联合信息技术有限公司', '2026-04-01', 500.00, '合同签订后7日内支付合同总额30%作为预付款；工程完工验收合格后支付60%；竣工结算审定后30日内付清余款10%。', '', '工程竣工验收合格后质保期1年。质保期内出现非人为损坏的质量问题，乙方免费上门维修。因甲方自行改动或人为损坏导致的故障不在免费质保范围内，按实际维修费用收取。', '', NULL, NULL, '按照GB50311综合布线系统工程验收规范及国家相关施工标准验收。工程竣工后乙方提交竣工报告及测试记录，甲方在5个工作日内组织验收，验收合格后双方签署竣工验收单作为最终结算依据。', '', 'onsite', 'draft', '', 1, '2026-04-01 13:41:55'),
(16, 'HT202604018503', 'outsource', 17, '汕头市云天联合咨询有限公司', '2026-04-01', 43200.00, '服务费按年收取，合同签订后7日内支付全年服务费。如按月收取，每月1日前支付当月服务费，逾期7日乙方有权暂停服务。', '', '乙方对服务过程中接触到的甲方业务数据、技术资料及商业信息严格保密，未经甲方书面许可不得向任何第三方披露或用于商业目的。合同终止后保密义务继续有效，期限为3年。', '', NULL, NULL, '', '一般故障：4小时内响应，24小时内解决；\r\n重大故障：2小时内响应，8小时内解决；\r\n紧急故障：30分钟内响应，4小时内解决。', 'onsite', 'draft', '', 1, '2026-04-01 13:47:16'),
(17, 'HT202604019738', 'rental', 33, '潮州市金桥明德设备有限公司', '2026-04-01', 9650.00, '租金按月支付，每月1日前支付当月租金，逾期超过7日加收滞纳金（按日租金的1‰计算）。', '设备由甲方送货上门，乙方验收签字后生效。租期届满前3日乙方应通知甲方安排取货，设备应保持完好归还。', '租赁期间因乙方原因造成设备损坏或丢失，乙方按设备市场估价赔偿。正常使用磨损不在赔偿范围内。', '', NULL, NULL, '', '', 'onsite', 'draft', '', 1, '2026-04-01 13:48:56'),
(18, 'ZL20260401141809', 'rental', 10, '珠海市华盛旭日设备有限公司', '2026-04-01', 610.00, '租金单价：¥50.00/月  租期：2026-04-01 至 2026-05-01  押金：¥200.00', '设备由甲方送货上门，验收签字后生效。', '租借期间设备出现非人为故障，由甲方负责维修。人为损坏或丢失按市场估价赔偿。', '', NULL, NULL, '', '', '', 'active', '由租赁合同 RT20260401141759 自动生成', 1, '2026-04-01 14:18:09'),
(20, 'HT202604015706', 'sales', 44, '东莞市宏图云天信息技术有限公司', '2026-04-01', 0.00, '合同签订后7日内支付合同总额50%作为预付款；货物发出前支付40%；验收合格后30日内付清余款10%。', '收到预付款后7个工作日内交付（定制产品30个工作日）。交付地点为乙方指定地址，运费由甲方承担。货物到达后甲方须在3个工作日内完成验收并签署验收单；逾期未提出异议视为验收合格。', '硬件产品自验收合格之日起质保1年，质保期内出现非人为故障由乙方免费维修或更换同等配置产品。软件产品提供6个月免费技术支持。耗材、易损件不在质保范围内。', '', NULL, NULL, '', '', 'onsite', 'draft', '', 1, '2026-04-01 17:14:30'),
