INSERT INTO `solutions` (`id`, `solution_no`, `solution_name`, `customer_id`, `customer_name`, `project_background`, `solution_content`, `status`, `remarks`, `created_by`, `created_at`, `updated_at`) VALUES
(1, 'FA2025110001', '中山网络优化方案', 28, '惠州市天成云天信息技术有限公司', '中山网络优化方案', '<p>中山网络优化方案  给您一些关于“<strong>方案管理</strong>”图标的建议，它们通常与<strong>想法</strong>、<strong>计划</strong>、<strong>解决问题</strong>或<strong>创新</strong>相关：</p><ul><li><strong>💡</strong> (<strong>灯泡</strong>): 代表“想法”、“灵感”或“解决方案”，非常符合“方案管理”的主题。</li><li><strong>📋</strong> (<strong>剪贴板</strong>): 也可以代表“计划”、“清单”或“文档”，但您已在“报价管理”中使用，如果想区分，可以考虑下一个。</li><li><strong>🧭</strong> (<strong>指南针</strong>): 象征“方向”、“规划”或“指引”，意味着为项目或问题找到方向。</li><li><strong>📐</strong> (<strong>三角尺/直尺</strong>): 表示“精确”、“测量”或“规划”。</li><li><strong>✅</strong> (<strong>白色复选标记/大对勾</strong>): 如果方案管理侧重于<strong>审批</strong>或<strong>完成</strong>。</li></ul><p><strong>推荐使用 💡 (灯泡)</strong>，因为它最能突出“方案”的核心——<strong>创新和解决问题</strong>。</p><p>以下是使用 <strong>💡</strong> 的更新代码：</p>', '草稿', '3434343', 1, '2025-11-09 14:39:35', '2026-04-04 13:23:18'),
(3, 'FA2026030001', '惠州保税仓监控方案', 28, '惠州市天成云天信息技术有限公司', '', '<p><br></p>', '草稿', '', 1, '2026-03-16 10:55:16', '2026-04-04 13:23:18'),
(5, 'FA2026030002', '惠州保税仓监控方案2266', 28, '惠州市天成云天信息技术有限公司', '', '', '草稿', '4354545', 1, '2026-03-19 16:22:51', '2026-04-04 13:23:18'),
(6, 'FA2026030003', '中山网络优化方案 (副本)', 33, '东莞市宏图云天信息技术有限公司', '3434', '433434', '草稿', '343434', 1, '2026-03-19 17:14:49', '2026-04-04 13:23:18'),
(7, 'FA202510010001', '深圳腾远科技办公网络升级方案', NULL, '深圳市腾远科技有限公司', '客户现有网络设备老化，带宽不足，影响日常办公效率，需要进行全面升级改造。', '一、项目概述：对客户现有办公网络进行全面升级，包括核心交换机、接入交换机、无线AP及防火墙设备更换。二、主要设备：华为S5735核心交换机×1、华为S2730接入交换机×4、华为AP6050无线AP×8、华为USG6305防火墙×1。三、实施计划：分两个阶段实施，第一阶段更换核心设备，第二阶段更换接入层设备。四、预算：设备费用约8.5万元，施工费用1.2万元，合计9.7万元。', '已提交', NULL, 1, '2025-10-05 09:00:00', '2026-04-05 12:16:54'),
(8, 'FA202510010002', '广州华盛信息服务器虚拟化方案', NULL, '广州华盛信息技术有限公司', '客户业务系统分散在多台物理服务器上，资源利用率低，维护成本高，需要进行虚拟化整合。', '一、项目概述：将客户现有8台物理服务器整合为3台高性能服务器，通过VMware vSphere实现虚拟化。二、主要设备：戴尔PowerEdge R740服务器×3、VMware vSphere企业版×3、共享存储设备×1。三、实施方案：迁移现有业务系统至虚拟机，实现高可用和负载均衡。四、预算：设备费用约22万元，软件费用8万元，实施费用3万元，合计33万元。', '已成交', NULL, 1, '2025-10-12 10:00:00', '2026-04-05 12:16:54'),
(9, 'FA202510010003', '东莞智汇网络安防监控系统方案', NULL, '东莞智汇网络科技有限公司', '客户园区现有监控设备陈旧，画质差，无法满足安全管理需求，需要全面升级监控系统。', '一、项目概述：在客户园区部署高清IP监控系统，覆盖主要出入口、走廊及重要区域。二、主要设备：海康威视200万像素摄像机×32、海康威视NVR录像机×2、监控显示屏×2、硬盘×8。三、实施方案：全新布线，安装调试，提供操作培训。四、预算：设备费用约6.8万元，施工费用1.5万元，合计8.3万元。', '草稿', NULL, 1, '2025-10-20 14:00:00', '2026-04-05 12:16:54'),
(10, 'FA202511010001', '珠海格力网络数据中心建设方案', NULL, '珠海格力网络有限公司', '客户需要新建一个小型数据中心，用于托管核心业务系统，要求高可用、高安全。', '一、项目概述：为客户建设小型数据中心，包括机房改造、UPS供电、精密空调、综合布线及网络设备部署。二、主要内容：机房装修改造、UPS不间断电源×2、精密空调×2、42U标准机柜×4、综合布线及网络设备。三、实施计划：工期约45天，分机房改造、设备安装、系统调试三个阶段。四、预算：约58万元。', '已提交', NULL, 1, '2025-11-06 09:00:00', '2026-04-05 12:16:54'),
(11, 'FA202511010002', '佛山盛达科技ERP系统部署方案', NULL, '佛山盛达科技有限公司', '客户需要部署企业ERP系统，需要配套的服务器、网络及存储设备支撑。', '一、项目概述：为客户ERP系统部署提供完整的IT基础架构支撑，包括服务器、存储、网络及安全设备。二、主要设备：联想ThinkSystem SR650服务器×2、存储设备×1、备份设备×1、交换机及防火墙各×1。三、实施方案：完成硬件部署后配合ERP厂商完成系统安装调试。四、预算：约35万元。', '已成交', NULL, 1, '2025-11-14 10:00:00', '2026-04-05 12:16:54'),
(12, 'FA202511010003', '深圳蓝海智能终端设备采购方案', NULL, '深圳蓝海智能科技有限公司', '客户新办公室装修完成，需要采购一批办公终端设备，包括电脑、打印机、投影仪等。', '一、项目概述：为客户新办公室配置完整的办公终端设备，满足50人规模的日常办公需求。二、主要设备：联想ThinkCentre台式机×30、联想ThinkPad笔记本×20、惠普打印机×5、投影仪×3、显示器×50。三、实施方案：统一采购、配置、安装调试，提供一年上门保修服务。四、预算：约48万元。', '草稿', NULL, 1, '2025-11-22 14:00:00', '2026-04-05 12:16:54'),
(13, 'FA202512010001', '广州粤海信息网络安全加固方案', NULL, '广州粤海信息技术有限公司', '客户近期遭受网络攻击，需要对现有网络安全架构进行全面加固，防止数据泄露。', '一、项目概述：对客户网络进行全面安全评估，并针对发现的安全漏洞进行加固处理。二、主要内容：防火墙升级、入侵检测系统部署、终端安全软件部署、员工安全培训。三、主要设备：深信服NGAF下一代防火墙×1、深信服EDR终端检测×50节点、态势感知平台×1。四、预算：约18万元。', '已提交', NULL, 1, '2025-12-03 09:00:00', '2026-04-05 12:16:54'),
(14, 'FA202512010002', '惠州博远信息云桌面解决方案', NULL, '惠州博远信息技术有限公司', '客户有大量外勤人员需要远程访问公司内网系统，需要部署云桌面解决方案。', '一、项目概述：为客户部署VDI云桌面系统，支持100个并发用户通过各类终端安全访问公司内网。二、主要设备：服务器×4、存储×1、云桌面软件100用户授权、瘦客户端×60。三、实施方案：部署云桌面平台，迁移现有应用，提供用户培训。四、预算：约42万元。', '已成交', NULL, 1, '2025-12-11 10:00:00', '2026-04-05 12:16:54'),
(15, 'FA202512010003', '中山恒信科技综合布线方案', NULL, '中山恒信科技有限公司', '客户新建厂房需要进行综合布线，包括网络、电话、监控等系统的布线工程。', '一、项目概述：为客户新建5000平米厂房提供综合布线解决方案，满足网络、电话、监控等需求。二、主要内容：超六类网络布线×300点、电话布线×100点、监控布线×50点、机柜及配线架安装。三、实施计划：工期约30天。四、预算：约15万元。', '草稿', NULL, 1, '2025-12-19 14:00:00', '2026-04-05 12:16:54'),
(16, 'FA202601010001', '深圳迅达科技灾备系统建设方案', NULL, '深圳迅达科技有限公司', '客户核心业务系统缺乏灾备保障，一旦主系统故障将造成业务中断，需要建立异地灾备系统。', '一、项目概述：为客户建立异地灾备系统，实现核心业务数据的实时备份和快速恢复。二、主要设备：备份服务器×2、备份软件×1、专线接入×1。三、实施方案：部署灾备系统，制定灾备演练方案，定期进行切换演练。四、预算：约28万元。', '已提交', NULL, 1, '2026-01-06 09:00:00', '2026-04-05 12:16:54'),
(17, 'FA202601010002', '广州联创信息智慧园区方案', NULL, '广州联创信息科技有限公司', '客户园区需要进行智慧化升级，实现门禁、停车、访客、安防等系统的统一管理。', '一、项目概述：为客户园区部署智慧管理平台，整合门禁、停车场、访客管理、视频监控等子系统。二、主要内容：智慧园区管理平台×1、人脸识别门禁×20套、停车场管理系统×1、访客管理系统×1。三、实施计划：工期约60天。四、预算：约65万元。', '已成交', NULL, 1, '2026-01-14 10:00:00', '2026-04-05 12:16:54'),
(18, 'FA202601010003', '东莞松山湖科技无线覆盖方案', NULL, '东莞松山湖科技有限公司', '客户办公区域无线信号覆盖不均匀，存在盲区，影响移动办公体验，需要重新规划无线网络。', '一、项目概述：对客户3000平米办公区域进行无线网络重新规划和部署，实现无缝漫游覆盖。二、主要设备：华为AP6150无线AP×15、华为AC6605无线控制器×1、POE交换机×2。三、实施方案：现场勘测，合理规划AP点位，完成安装调试。四、预算：约8.5万元。', '草稿', NULL, 1, '2026-01-21 14:00:00', '2026-04-05 12:16:54'),
(19, 'FA202602010001', '深圳华越科技存储扩容方案', NULL, '深圳华越科技有限公司', '客户现有存储容量不足，业务数据增长迅速，需要进行存储扩容和升级。', '一、项目概述：对客户现有存储系统进行扩容，同时升级存储架构，提升IO性能和可靠性。二、主要设备：全闪存储扩容模块×2、备份一体机×1。三、实施方案：在线扩容，不影响现有业务运行。四、预算：约32万元。', '已提交', NULL, 1, '2026-02-05 09:00:00', '2026-04-05 12:16:54'),
(20, 'FA202602010002', '广州越秀数码办公自动化方案', NULL, '广州越秀数码科技有限公司', '客户需要对现有办公流程进行数字化改造，实现无纸化办公和流程自动化。', '一、项目概述：为客户部署OA办公自动化系统，并配套相应的扫描仪、打印机等硬件设备。二、主要内容：OA系统部署×1套、高速扫描仪×5、多功能复合机×3、电子签章系统×1。三、实施方案：系统部署、数据迁移、员工培训。四、预算：约22万元。', '已成交', NULL, 1, '2026-02-12 10:00:00', '2026-04-05 12:16:54'),
(21, 'FA202602010003', '佛山南海数据中心运维服务方案', NULL, '佛山南海数据技术有限公司', '客户数据中心缺乏专业运维团队，需要外包专业运维服务，保障系统稳定运行。', '一、项目概述：为客户提供数据中心7×24小时专业运维服务，包括日常巡检、故障处理、性能优化等。二、服务内容：驻场运维工程师×2名、远程监控平台×1套、月度运维报告。三、服务期限：一年，可续签。四、预算：年服务费约36万元。', '草稿', NULL, 1, '2026-02-20 14:00:00', '2026-04-05 12:16:54'),
(22, 'FA202603010001', '深圳前海科技混合云架构方案', NULL, '深圳前海科技有限公司', '客户希望将部分业务迁移至云端，同时保留核心数据在本地，需要构建混合云架构。', '一、项目概述：为客户构建混合云架构，实现本地数据中心与公有云的互联互通。二、主要内容：本地私有云平台搭建、专线接入公有云、统一管理平台部署。三、主要设备：高性能服务器×3、专线接入×1、混合云管理平台×1。四、预算：约55万元。', '已提交', NULL, 1, '2026-03-04 09:00:00', '2026-04-05 12:16:54'),
(23, 'FA202603010002', '广州南沙智慧城市项目方案', NULL, '广州南沙智慧城市建设有限公司', '客户承接智慧城市建设项目，需要采购一批网络设备和服务器用于项目实施。', '一、项目概述：为智慧城市项目提供核心网络和计算设备，支撑城市管理平台的运行。二、主要设备：华为核心路由器×2、华为核心交换机×4、服务器×10、存储设备×2。三、实施计划：按项目进度分批交付。四、预算：约180万元。', '已成交', NULL, 1, '2026-03-11 10:00:00', '2026-04-05 12:16:54'),
(24, 'FA202603010003', '东莞虎门数码零售终端改造方案', NULL, '东莞虎门数码科技有限公司', '客户连锁门店需要对收银系统和终端设备进行统一升级，提升收银效率和数据管理能力。', '一、项目概述：为客户20家连锁门店统一更换收银终端和后台管理系统。二、主要设备：收银一体机×40台、扫码枪×40把、小票打印机×40台、后台管理服务器×2。三、实施方案：分批到店安装调试，员工培训。四、预算：约38万元。', '草稿', NULL, 1, '2026-03-19 14:00:00', '2026-04-05 12:16:54'),
(25, 'FA202604010001', '深圳坪山科技5G专网方案', NULL, '深圳坪山科技有限公司', '客户工厂需要部署5G专网，支撑工业互联网应用，实现设备互联和数据采集。', '一、项目概述：为客户工厂部署5G专网，实现AGV小车、工业相机、传感器等设备的无线连接。二、主要设备：5G基站×4、5G核心网设备×1、5G工业网关×20。三、实施计划：工期约90天。四、预算：约320万元。', '已提交', NULL, 1, '2026-04-02 09:00:00', '2026-04-05 12:16:54'),
(26, 'FA202604010002', '广州黄埔智联数字化转型方案', NULL, '广州黄埔智联科技有限公司', '客户制造业企业需要进行数字化转型，实现生产数据的采集、分析和可视化管理。', '一、项目概述：为客户部署工业数据采集平台，实现生产线数据实时采集和分析。二、主要内容：工业数据采集网关×30、边缘计算服务器×5、数据分析平台×1、大屏展示系统×1。三、实施方案：按生产线逐步推进。四、预算：约95万元。', '草稿', NULL, 1, '2026-04-03 10:00:00', '2026-04-05 12:16:54'),
(27, 'FA202604010003', '佛山禅城数据安全合规方案', NULL, '佛山禅城数据科技有限公司', '客户受数据安全法规约束，需要对数据处理流程进行合规改造，建立数据安全管理体系。', '一、项目概述：协助客户建立符合数据安全法要求的数据安全管理体系，并部署相应的技术措施。二、主要内容：数据分类分级系统×1、数据防泄露DLP系统×1、数据库审计系统×1、安全培训。三、实施计划：工期约45天。四、预算：约26万元。', '草稿', NULL, 1, '2026-04-04 14:00:00', '2026-04-05 12:16:54');
